SELECT CASE WHEN COUNT(*) > 0 THEN 1 ELSE 0 END
FROM space_members
WHERE space_key = #{spaceKey}
AND user_no = #{userNo}


SELECT COUNT(*) 
FROM space_members 
WHERE invite_code = #{inviteCode} 
AND expire_date > SYSDATE 
AND user_no = #{userNo} 
AND space_key = #{spaceKey}

mapper.update:

UPDATE space_members 
